REQUIREMENTS = "pandas>=1.5\nopenpyxl>=3.0\nfredapi>=0.5\n"

_SRC = {
    'keybank_style': KEYBANK_STYLE_B64,
    'series_seed': SERIES_SEED_B64,
    'runner': RUNNER_B64,
    'build_workbook': BUILD_WORKBOOK_B64,
}

def _decode(b): return gzip.decompress(base64.b64decode(b)).decode("utf-8")

def _write(path, text):
    with open(path, "w", encoding="utf-8", newline="\n") as fh:
        fh.write(text)

def main():
    cwd = os.getcwd()
    # 1) drop the source files the build + refresh need
    _write(os.path.join(cwd, "runner.py"), _decode(RUNNER_B64))
    _write(os.path.join(cwd, "macro.bas"), _decode(MACRO_B64))
    _write(os.path.join(cwd, "requirements.txt"), REQUIREMENTS)
    # 2) register the modules from embedded source (no import from disk)
    for name in ("keybank_style", "series_seed", "runner", "build_workbook"):
        m = types.ModuleType(name)
        m.__file__ = os.path.join(cwd, name + ".py")
        sys.modules[name] = m
        exec(compile(_decode(_SRC[name]), name + ".py", "exec"), m.__dict__)
    # 3) build the workbook, then demo-populate so it opens showing data
    out = os.path.join(cwd, "FRED_Credit_Risk_Dashboard.xlsx")
    sys.modules["build_workbook"].build(out)
    sys.modules["runner"].run(out, backend_name="openpyxl", demo=True)
    print("Built:", out)
    print("Also wrote runner.py, macro.bas, requirements.txt in", cwd)
    print("Open the .xlsx. For live data: set FRED_API_KEY and run runner.py (see --help).")

if __name__ == "__main__":
    try:
        main()
    except ImportError as e:
        sys.stderr.write("Missing dependency: %s\nRun: python -m pip install pandas openpyxl\n" % e)
        sys.exit(1)
